{
  "global": "Navigate to the music application's listening history section and delete all recently played tracks.",
  "subtasks": [
    {
      "subtask": "Open the music application and ensure the user is authenticated",
      "atomics": [
        "Navigate to the music platform URL in the browser",
        "Verify the user is logged in; submit credentials if a login form is present"
      ]
    },
    {
      "subtask": "Locate the recently played / listening history section",
      "atomics": [
        "Click on the user profile icon or account menu to open user options",
        "Identify and click the 'Recently Played', 'History', or equivalent navigation item",
        "Confirm the history list is visible and populated with track entries"
      ]
    },
    {
      "subtask": "Trigger the delete or clear history action",
      "atomics": [
        "Locate the 'Clear history', 'Delete history', or equivalent button/option on the history page",
        "Click the clear/delete control to initiate removal",
        "Confirm any confirmation dialog (e.g., click 'Yes', 'Confirm', or 'Delete') to finalize deletion"
      ]
    }
  ],
  "global_atomics": [
    "Verify the recently played list is now empty or shows a 'No history' placeholder after deletion"
  ],
  "gold_actions": {
    "global": "Click through the music app's account/history UI to find and execute the clear-listening-history action, then confirm the modal.",
    "subtasks": [
      {
        "subtask": "Open the music application and ensure the user is authenticated",
        "atomics": [
          "Type the music platform URL into the address bar and press Enter",
          "If redirected to login, fill email/username and password fields and click 'Log In'"
        ]
      },
      {
        "subtask": "Locate the recently played / listening history section",
        "atomics": [
          "Click the user avatar or profile icon in the top-right navigation bar",
          "Click 'History' or 'Recently Played' from the dropdown or sidebar menu",
          "Assert that a list of recently played tracks is rendered on screen"
        ]
      },
      {
        "subtask": "Trigger the delete or clear history action",
        "atomics": [
          "Click the 'Clear All' / 'Delete History' / trash-icon button visible on the history page",
          "Click the primary action button in the confirmation modal (e.g., 'Clear', 'Delete', 'Confirm')",
          "Wait for the UI to update and the history list to be removed"
        ]
      }
    ],
    "global_atomics": [
      "Assert the recently played section displays an empty state message (e.g., 'No listening history') confirming successful deletion"
    ]
  }
}
